"use strict";(self.webpackChunknunix_github_io=self.webpackChunknunix_github_io||[]).push([[477],{10:e=>{e.exports=JSON.parse('{"blogPosts":[{"id":"/2022/07/25/welcome","metadata":{"permalink":"/blog/2022/07/25/welcome","editUrl":"https://github.com/facebook/docusaurus/tree/main/packages/create-docusaurus/templates/shared/blog/2022-07-25-welcome.md","source":"@site/blog/2022-07-25-welcome.md","title":"The Corsair\'s Logbook","description":"I always like to write about the technologies I test/use as it gives me the opportunity of writing about \\"a thing\\" in my own way, telling a story.","date":"2022-07-25T00:00:00.000Z","formattedDate":"July 25, 2022","tags":[],"readingTime":0.76,"hasTruncateMarker":false,"authors":[{"name":"Nuno do Carmo","title":"The Captain Corsair","url":"https://github.com/nunix","imageURL":"https://github.com/nunix.png","key":"corsair"}],"frontMatter":{"authors":"corsair"}},"content":"I always like to write about the technologies I test/use as it gives me the opportunity of writing about \\"a thing\\" in my own way, telling a story.\\r\\nThat\'s how personally, I learn best. I mean, I look at a blog post and see the chapters, maybe I already know some of them and move ahead or tell myself \\"is there a detail I missed last time I read\\"?\\r\\n\\r\\nSo the question is: how does other relate to my technical blog posts? Do they relate to the story? Did they learn something?\\r\\n\\r\\nWhile I can\'t be in the heads of the readers, I definitively can convey my own side of the story and what, as the Captain Corsair, I went through ... but not only.\\r\\n\\r\\nSo welcome to this more personal side of the Corsair, and if you found this Logbook, let me know on [Twitter](https://twitter.com/nunixtech) what you thought.\\r\\n\\r\\nThe Captain Corsair"}]}')}}]);